var pallets = [];
var vendors = [];
var editingId = null;
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function statusBadge(s) {
  var cls = {
    open: 'badge-open',
    closed: 'badge-closed',
    collected: 'badge-collected'
  };
  return '<span class="badge ' + (cls[s] || 'badge-open') + '">' + (s || 'open') + '</span>';
}
function wasteTypeLabel(t) {
  var map = {
    mixed_electrical: 'Mixed Electrical',
    hazardous: 'Hazardous',
    battery: 'Battery',
    other: 'Other'
  };
  return '<span class="waste-type">' + (map[t] || t || '—') + '</span>';
}
function populateVendors(sel, selected) {
  if (!sel) return;
  sel.innerHTML = '<option value="">Select vendor...</option>' + vendors.map(function (v) {
    return '<option value="' + v.vendor_id + '"' + (selected == v.vendor_id ? ' selected' : '') + '>' + v.name + '</option>';
  }).join('');
}
function render(model) {
  pallets = model.pallets || [];
  vendors = model.vendors || [];
  var tbody = document.getElementById('table_body');
  if (!tbody) return;
  if (!pallets.length) {
    tbody.innerHTML = '<tr><td colspan="9" class="empty">No waste pallets yet</td></tr>';
    return;
  }
  tbody.innerHTML = pallets.map(function (p, i) {
    return '<tr>' + '<td><span class="waste-id">' + (p.waste_id || '—') + '</span></td>' + '<td>' + wasteTypeLabel(p.waste_type) + '</td>' + '<td>' + statusBadge(p.status) + '</td>' + '<td>' + (p.vendor_name || '<span style="color:#9ca3af">—</span>') + '</td>' + '<td>' + (p.item_count || 0) + '</td>' + '<td>' + (p.weight_kg ? p.weight_kg + ' kg' : '—') + '</td>' + '<td>' + fmt(p.created_date) + '</td>' + '<td>' + fmt(p.collection_date) + '</td>' + '<td>' + '<button class="btn-sm btn-edit" onclick="window.editPallet(' + i + ')">Edit</button>' + '<button class="btn-sm btn-view" onclick="window.openPallet(' + i + ')">View</button>' + '</td>' + '</tr>';
  }).join('');
}
function showEditFields(show) {
  ['f_vendor_group', 'f_weight_group', 'f_collection_group', 'f_status_group'].forEach(function (id) {
    document.getElementById(id).style.display = show ? 'flex' : 'none';
  });
}
window.openForm = function () {
  editingId = null;
  document.getElementById('form_title').textContent = 'New Waste Pallet';
  document.getElementById('f_waste_type').value = 'mixed_electrical';
  document.getElementById('f_notes').value = '';
  document.getElementById('f_weight').value = '';
  document.getElementById('f_collection_date').value = '';
  document.getElementById('f_status').value = 'open';
  showEditFields(false);
  document.getElementById('form_panel').classList.add('open');
};
window.closeForm = function () {
  document.getElementById('form_panel').classList.remove('open');
};
window.editPallet = function (i) {
  var p = pallets[i];
  if (!p) return;
  editingId = p.pallet_id;
  document.getElementById('form_title').textContent = 'Edit — ' + p.waste_id;
  document.getElementById('f_waste_type').value = p.waste_type || 'mixed_electrical';
  document.getElementById('f_notes').value = p.notes || '';
  document.getElementById('f_weight').value = p.weight_kg || '';
  document.getElementById('f_collection_date').value = p.collection_date ? p.collection_date.split('T')[0] : '';
  document.getElementById('f_status').value = p.status || 'open';
  showEditFields(true);
  populateVendors(document.getElementById('f_vendor'), p.vendor_id);
  document.getElementById('form_panel').classList.add('open');
};
window.openPallet = function (i) {
  var p = pallets[i];
  if (!p) return;
  appsmith.updateModel({
    selected_pallet: p
  });
  appsmith.triggerEvent('onViewPallet');
};
window.savePallet = function () {
  var vid = document.getElementById('f_vendor').value;
  var w = document.getElementById('f_weight').value;
  var cd = document.getElementById('f_collection_date').value;
  appsmith.updateModel({
    pallet_id: editingId,
    pallet_waste_type: document.getElementById('f_waste_type').value,
    pallet_vendor_id: vid ? parseInt(vid) : null,
    pallet_weight: w ? parseFloat(w) : null,
    pallet_collection_date: cd || null,
    pallet_status: document.getElementById('f_status').value || 'open',
    pallet_notes: document.getElementById('f_notes').value,
    is_edit: editingId !== null
  });
  appsmith.triggerEvent('onSavePallet');
  window.closeForm();
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

